// Webhook data can arrive in body, query parameters, route params, or top-level fields.
// Roma sends values as parameters, so do not read only $json.body.
const topLevel = Object.fromEntries(
  Object.entries($json || {}).filter(([k]) => !['body', 'query', 'params', 'headers'].includes(k))
);
const payload = {
  ...($json.query || {}),
  ...($json.params || {}),
  ...($json.body || {}),
  ...topLevel,
};

function pick(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v) !== '' && String(v) !== 'undefined') return v;
  }
  return undefined;
}

function nowIso() {
  return new Date().toISOString();
}

function normalizeStatusKey(key) {
  return String(key ?? '')
    .trim()
    .toLowerCase()
    .replace(/[\s\-]+/g, '_')
    .replace(/[^a-z0-9_]/g, '');
}

function addStatus(out, key, value) {
  const k = normalizeStatusKey(key);
  if (!k) return;
  if (value === undefined || value === null || String(value) === '' || String(value) === 'undefined') return;
  out[k] = String(value);
}

function parseJsonObject(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  if (typeof v === 'string') {
    try {
      const parsed = JSON.parse(v);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
    } catch (e) {}
  }
  return {};
}

function normalizeBisapiUrl(v) {
  let url = String(v ?? '').trim();
  if (!url || url === 'undefined') return 'http://lease4.mekashron.com:33330/soap/IBusinessAPI';
  url = url.replace(/\/+$/, '');
  if (/\/soap\/IBusinessAPI$/i.test(url)) return url;
  return `${url}/soap/IBusinessAPI`;
}

function makeScopeKey(bisapiUrl, businessId, campaignId) {
  return `${normalizeBisapiUrl(bisapiUrl)}:${businessId}:${campaignId}`;
}

function toMs(v) {
  const ms = Date.parse(String(v ?? ''));
  return Number.isFinite(ms) ? ms : null;
}

function normalizeStopRecord(raw) {
  // Backward compatibility with the old boolean stop flag.
  // Old true has no timestamp, so we treat it as very old; new runs ignore it.
  if (raw === true) {
    return {
      active: true,
      updated_at: '1970-01-01T00:00:00.000Z',
      legacy_boolean: true,
    };
  }

  if (raw === false || raw === undefined || raw === null) {
    return {
      active: false,
      updated_at: '',
      legacy_boolean: raw === false,
    };
  }

  if (typeof raw === 'object') {
    return {
      active: raw.active === true,
      updated_at: String(raw.updated_at || raw.stopped_at || ''),
      run_started_at: String(raw.run_started_at || ''),
      source_command: String(raw.source_command || ''),
      raw,
    };
  }

  return {
    active: false,
    updated_at: '',
    raw,
  };
}

function isStopActiveForRun(rawStop, runStartedAt) {
  const stop = normalizeStopRecord(rawStop);
  if (!stop.active) {
    return { active: false, stale: false, stop };
  }

  const stopMs = toMs(stop.updated_at);
  const runMs = toMs(runStartedAt);

  // If the current run has no timestamp, be conservative and honor active stop.
  if (runMs === null) {
    return { active: true, stale: false, stop, reason: 'no_run_started_at' };
  }

  // Legacy boolean true is considered stale for any new timestamped run.
  if (stop.legacy_boolean === true) {
    return { active: false, stale: true, stop, reason: 'legacy_boolean_stop_is_stale' };
  }

  // If active stop has no valid timestamp, be conservative.
  if (stopMs === null) {
    return { active: true, stale: false, stop, reason: 'stop_has_no_valid_updated_at' };
  }

  if (stopMs >= runMs) {
    return { active: true, stale: false, stop, reason: 'stop_after_or_equal_run_start' };
  }

  return { active: false, stale: true, stop, reason: 'stop_before_run_start' };
}

function getStopCheck(stopFlags, key, legacyKey, runStartedAt) {
  const primary = isStopActiveForRun(stopFlags[key], runStartedAt);
  const legacy = isStopActiveForRun(stopFlags[legacyKey], runStartedAt);
  const active = primary.active || legacy.active;

  return {
    active,
    stop_flag: active,
    should_continue: !active,
    primary,
    legacy,
    stop_updated_at: primary.stop.updated_at || legacy.stop.updated_at || '',
    stale_stop_ignored: Boolean(primary.stale || legacy.stale),
  };
}

function normalizeIncomingStatusMap(payload) {
  const out = {};

  // Fixed CRM tStatusID values from curator.
  addStatus(out, 'no_answer', 1);
  addStatus(out, 'busy', 2);
  addStatus(out, 'invalid_phone', 3);
  addStatus(out, 'fax', 4);
  addStatus(out, 'answering_machine', 5);

  const maps = [
    parseJsonObject(payload.status_map),
    parseJsonObject(payload.statusMap),
    parseJsonObject(payload.statuses),
    parseJsonObject(payload.status_ids),
    parseJsonObject(payload.statusIds),
    parseJsonObject(payload.crm_status_map),
    parseJsonObject(payload.crmStatusMap),
  ];

  for (const m of maps) {
    for (const [k, v] of Object.entries(m)) addStatus(out, k, v);
  }

  addStatus(out, 'no_answer', pick(payload.fixed_no_answer_tStatusID, payload.no_answer_tStatusID, payload.no_answer_status_id, payload.noAnswerStatusId));
  addStatus(out, 'busy', pick(payload.fixed_busy_tStatusID, payload.busy_tStatusID, payload.busy_status_id, payload.busyStatusId));
  addStatus(out, 'invalid_phone', pick(payload.fixed_invalid_phone_tStatusID, payload.invalid_phone_tStatusID, payload.invalid_phone_status_id, payload.invalidPhoneStatusId));
  addStatus(out, 'fax', pick(payload.fixed_fax_tStatusID, payload.fax_tStatusID, payload.fax_status_id, payload.faxStatusId));
  addStatus(out, 'answering_machine', pick(payload.fixed_answering_machine_tStatusID, payload.answering_machine_tStatusID, payload.answering_machine_status_id, payload.answeringMachineStatusId));

  addStatus(out, 'answered', pick(payload.answered_status_id, payload.answeredStatusId, payload.completed_status_id, payload.completedStatusId, payload.success_status_id, payload.successStatusId));
  addStatus(out, 'success', pick(payload.success_status_id, payload.successStatusId, payload.answered_status_id, payload.answeredStatusId, payload.completed_status_id, payload.completedStatusId));
  addStatus(out, 'completed', pick(payload.completed_status_id, payload.completedStatusId, payload.answered_status_id, payload.answeredStatusId, payload.success_status_id, payload.successStatusId));
  addStatus(out, 'failed', pick(payload.failed_status_id, payload.failedStatusId, payload.fail_status_id, payload.failStatusId));
  addStatus(out, 'failed_start', pick(payload.failed_start_status_id, payload.failedStartStatusId, payload.failed_outbound_status_id, payload.failedOutboundStatusId));
  addStatus(out, 'not_interested', pick(payload.not_interested_status_id, payload.notInterestedStatusId));
  addStatus(out, 'confirm', pick(payload.confirm_status_id, payload.confirmStatusId));
  addStatus(out, 'call_back', pick(payload.call_back_status_id, payload.callback_status_id, payload.callBackStatusId, payload.callbackStatusId));

  return out;
}

function mergeStatusMaps(...maps) {
  const out = {};
  for (const m of maps) {
    if (!m || typeof m !== 'object') continue;
    for (const [k, v] of Object.entries(m)) addStatus(out, k, v);
  }
  return out;
}

function normalizeEntityIds(v) {
  if (v === undefined || v === null || String(v) === '' || String(v) === 'undefined') return [];
  const raw = Array.isArray(v) ? v : String(v).split(',');
  return raw.map(x => String(x).trim()).filter(Boolean);
}

function positiveInt(v, fallback = 1) {
  const n = Math.floor(Number(v));
  if (!Number.isFinite(n) || n < 1) return fallback;
  return n;
}

function clampInt(v, min, max, fallback = min) {
  const n = positiveInt(v, fallback);
  return Math.max(min, Math.min(max, n));
}

function boolParam(v, fallback = false) {
  if (v === undefined || v === null || String(v) === '' || String(v) === 'undefined') return fallback;
  const s = String(v).trim().toLowerCase();
  if (['true', '1', 'yes', 'on'].includes(s)) return true;
  if (['false', '0', 'no', 'off'].includes(s)) return false;
  return Boolean(v);
}

const BusinessId = String(pick(payload.BusinessId, payload.business_id, payload.businessId, 1));
const CampaignID = String(pick(payload.CampaignID, payload.campaignID, payload.campaign_id, 12));
const incomingUserID = pick(payload.userID, payload.userId, payload.UserID);
const incomingUserIDProvided = incomingUserID !== undefined && incomingUserID !== null && String(incomingUserID) !== '' && String(incomingUserID) !== 'undefined';
const userID = String(pick(incomingUserID, 1));
const command = String(pick(payload.command, 'start')).toLowerCase().trim();
const business_api_url = normalizeBisapiUrl(pick(payload.BISAPI_URL, payload.bisapi_url, payload.business_api_url, payload.crm_url, payload.web_service_url));
const key = makeScopeKey(business_api_url, BusinessId, CampaignID);
const legacyKey = `${BusinessId}:${CampaignID}`;

const staticData = $getWorkflowStaticData('global');
staticData.telemarketing = staticData.telemarketing || {};
staticData.telemarketing.stopFlags = staticData.telemarketing.stopFlags || {};
staticData.telemarketing.activeCalls = staticData.telemarketing.activeCalls || {};
staticData.telemarketing.lastSummaries = staticData.telemarketing.lastSummaries || {};
staticData.telemarketing.completedOutgoing = staticData.telemarketing.completedOutgoing || {};
staticData.telemarketing.campaignStatusMaps = staticData.telemarketing.campaignStatusMaps || {};
staticData.telemarketing.currentRuns = staticData.telemarketing.currentRuns || {};

const currentRun = staticData.telemarketing.currentRuns[key] || staticData.telemarketing.currentRuns[legacyKey] || {};
const incomingRunStartedAt = pick(payload.run_started_at, payload.runStartedAt, payload.current_run_started_at, payload.currentRunStartedAt);
const runStartedAt = String(pick(
  incomingRunStartedAt,
  command === 'continue' ? currentRun.run_started_at : undefined,
  command === 'start' || command === 'resume' ? nowIso() : undefined,
  ''
));

if (command === 'reset_completed') {
  const prefixes = [`${key}:`, `${legacyKey}:`];
  let removed = 0;
  for (const k of Object.keys(staticData.telemarketing.completedOutgoing)) {
    if (prefixes.some(prefix => k.startsWith(prefix))) {
      delete staticData.telemarketing.completedOutgoing[k];
      removed++;
    }
  }
  return [{ json: { command, BusinessId, CampaignID, userID, business_api_url, status_map_storage_key: key, should_continue: false, message: `Completed outgoing guard reset for campaign ${key}`, removed_completed_records: removed } }];
}

if (command === 'reset_status_map') {
  delete staticData.telemarketing.campaignStatusMaps[key];
  delete staticData.telemarketing.campaignStatusMaps[legacyKey];
  return [{ json: { command, BusinessId, CampaignID, userID, business_api_url, status_map_storage_key: key, should_continue: false, message: `Status map reset for campaign ${key}` } }];
}

const fixedAndIncomingStatusMap = normalizeIncomingStatusMap(payload);
const storedStatusMap = staticData.telemarketing.campaignStatusMaps[key]?.status_map || staticData.telemarketing.campaignStatusMaps[legacyKey]?.status_map || {};
const status_map = mergeStatusMaps(fixedAndIncomingStatusMap, storedStatusMap, fixedAndIncomingStatusMap);

staticData.telemarketing.campaignStatusMaps[key] = {
  BISAPI_URL: business_api_url,
  BusinessId,
  CampaignID,
  status_map,
  updated_at: nowIso(),
  source: 'start_webhook_or_manual_input',
};

if (command === 'show_status_map' || command === 'save_status_map') {
  return [{ json: { command, BusinessId, CampaignID, userID, business_api_url, status_map_storage_key: key, should_continue: false, status_map, message: `Status map stored for campaign ${key}` } }];
}

if (command === 'stop') {
  const stoppedAt = nowIso();
  const stopRecord = {
    active: true,
    updated_at: stoppedAt,
    run_started_at: String(pick(incomingRunStartedAt, currentRun.run_started_at, '')),
    source_command: 'stop',
    BusinessId,
    CampaignID,
    userID,
    BISAPI_URL: business_api_url,
  };

  staticData.telemarketing.stopFlags[key] = stopRecord;
  staticData.telemarketing.stopFlags[legacyKey] = stopRecord;

  return [{
    json: {
      command,
      BusinessId,
      CampaignID,
      userID,
      business_api_url,
      BISAPI_URL: business_api_url,
      stop_key: key,
      legacy_stop_key: legacyKey,
      status_map_storage_key: key,
      run_started_at: stopRecord.run_started_at,
      stop_flag: true,
      stop_updated_at: stoppedAt,
      should_continue: false,
      message: `Stop flag set for campaign ${key}`,
    }
  }];
}

if (command === 'start' || command === 'resume' || (command === 'continue' && runStartedAt)) {
  const runRecord = {
    run_started_at: runStartedAt || nowIso(),
    updated_at: nowIso(),
    command,
    BusinessId,
    CampaignID,
    userID,
    BISAPI_URL: business_api_url,
  };
  staticData.telemarketing.currentRuns[key] = runRecord;
  staticData.telemarketing.currentRuns[legacyKey] = runRecord;
}

const stopCheck = getStopCheck(staticData.telemarketing.stopFlags, key, legacyKey, runStartedAt);

const defaultFinalStatusId = String(pick(
  payload.default_final_status_id,
  payload.final_status_id,
  status_map.answered,
  status_map.success,
  status_map.completed,
  '0'
));

const failedStartStatusId = String(pick(
  payload.failed_start_status_id,
  payload.failed_outbound_status_id,
  status_map.failed_start,
  status_map.failed,
  defaultFinalStatusId,
  '0'
));

const entity_ids = normalizeEntityIds(pick(
  payload.EntityIDs,
  payload.entity_ids,
  payload.entityIDs,
  payload.EntityId,
  payload.EntityID,
  payload.entity_id,
  payload.entityID
));

const defaultSelfStartWebhookUrl = 'https://n8n.mekashron.com/webhook/telemarketing-elevenlabs-start';

const autoContinueAfterCallback = boolParam(pick(
  payload.auto_continue_after_callback,
  payload.autoContinueAfterCallback,
  payload.auto_continue,
  payload.autoContinue
), false);

const selfStartWebhookUrl = autoContinueAfterCallback
  ? String(pick(
      payload.self_start_webhook_url,
      payload.selfStartWebhookUrl,
      payload.self_start_url,
      payload.selfStartUrl,
      defaultSelfStartWebhookUrl
    ))
  : String(pick(
      payload.self_start_webhook_url,
      payload.selfStartWebhookUrl,
      payload.self_start_url,
      payload.selfStartUrl,
      ''
    ));

const requestedParallelCalls = positiveInt(pick(
  payload['parallel-calls'],
  payload.parallel_calls,
  payload.parallelCalls,
  payload.limit_count,
  payload.limitCount,
  1
), 1);

const maxParallelCalls = 3;
const parallelCalls = Math.min(requestedParallelCalls, maxParallelCalls);

const requestedCrmFetchLimit = positiveInt(pick(
  payload.crm_fetch_limit,
  payload.fetch_limit,
  payload.queue_fetch_limit,
  payload.crmFetchLimit,
  payload.fetchLimit,
  100
), 100);

const crmFetchLimit = clampInt(requestedCrmFetchLimit, parallelCalls, 100, 100);

const out = {
  command,
  internal_auto_continue: boolParam(payload.internal_auto_continue, false),
  BusinessId,
  CampaignID,
  userID,
  incoming_user_id_provided: incomingUserIDProvided,
  user_id_filter_enabled: incomingUserIDProvided,
  BISAPI_URL: business_api_url,
  business_api_url,
  stop_key: key,
  legacy_stop_key: legacyKey,
  run_started_at: runStartedAt,
  current_run_started_at: runStartedAt,
  stop_flag: stopCheck.stop_flag,
  should_continue: stopCheck.should_continue,
  stop_updated_at: stopCheck.stop_updated_at,
  stale_stop_ignored: stopCheck.stale_stop_ignored,
  stop_check_debug: stopCheck,
  business_entity_id: String(pick(payload.business_entity_id, payload.ol_EntityID, payload.ol_EntityId, '27827')),
  business_username: String(pick(payload.business_username, payload.ol_Username, payload.ol_UserName, '442033973506')),
  business_password: String(pick(payload.business_password, payload.ol_Password, payload.ol_password, '123456')),
  station_id: String(pick(payload.station_id, payload.StationID, '1000')),
  list_type: String(pick(payload.list_type, 0)),
  limit_from: String(pick(payload.limit_from, 0)),
  limit_count: String(crmFetchLimit),
  crm_fetch_limit: String(crmFetchLimit),
  requested_crm_fetch_limit: String(requestedCrmFetchLimit),
  parallel_calls: String(parallelCalls),
  requested_parallel_calls: String(requestedParallelCalls),
  max_parallel_calls: String(maxParallelCalls),
  parallel_calls_capped: requestedParallelCalls > parallelCalls,
  entity_ids,
  agent_id: String(pick(payload.agent_id, 'agent_1801ksmne3yxewfvjtgsfbf5g8d0')),
  agent_phone_number_id: String(pick(payload.agent_phone_number_id, 'phnum_0901kq9t8q3mfnva3efwmj2a7yjj')),
  elevenlabs_api_key_for_crm: String(pick(payload.elevenlabs_api_key_for_crm, payload.api_key, '')),
  default_final_status_id: defaultFinalStatusId,
  failed_start_status_id: failedStartStatusId,
  auto_continue_after_callback: autoContinueAfterCallback,
  self_start_webhook_url: selfStartWebhookUrl,
  status_map,
  status_map_storage_key: key,
  use_completed_guard: ['true','1','yes','on'].includes(String(pick(payload.use_completed_guard, payload.useCompletedGuard, false)).trim().toLowerCase()),
};

return [{ json: out }];

function esc(v) {
  return String(v ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}
function arr(items) {
  return items.map(v => `<item xsi:type="xsd:string">${esc(v)}</item>`).join('\n');
}

const fields = [
  't.TelOutgoingID',
  't.CampaignID',
  't.EntityID',
  't.StationID',
  't.userID',
  't.ScheduleTo',
  'e.Phone',
  'e.Mobile',
  'e.FirstName',
  'e.LastName',
  'e.Email',
];

const filterFields = ['t.CampaignID'];
const filterValues = [String($json.CampaignID)];

// Curator decision: if userID is provided in the start request/querystring,
// it must be used in Telemarketing_Outgoing_Get filtering.
// Do not add this filter when userID is only the internal fallback/default.
if ($json.user_id_filter_enabled && String($json.userID ?? '').trim() !== '') {
  filterFields.push('t.userID');
  filterValues.push(String($json.userID));
}

// Optional direct EntityID filter. Use only when the CRM explicitly sends EntityID(s).
// There is no hardcoded EntityID here anymore.
if (Array.isArray($json.entity_ids) && $json.entity_ids.length === 1) {
  filterFields.push('t.EntityID');
  filterValues.push(String($json.entity_ids[0]));
}

const soapBody = `<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/"
  xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
  xmlns:xsd="http://www.w3.org/2001/XMLSchema"
  xmlns:ns1="urn:BusinessApiIntf-IBusinessAPI"
  xmlns:ns2="urn:CommonWSTypes">
  <soap:Body>
    <ns1:Telemarketing_Outgoing_Get soap:encodingStyle="http://schemas.xmlsoap.org/soap/encoding/">
      <ol_EntityID xsi:type="xsd:int">${esc($json.business_entity_id)}</ol_EntityID>
      <ol_Username xsi:type="xsd:string">${esc($json.business_username)}</ol_Username>
      <ol_Password xsi:type="xsd:string">${esc($json.business_password)}</ol_Password>
      <BusinessId xsi:type="xsd:int">${esc($json.BusinessId)}</BusinessId>
      <list_type xsi:type="xsd:int">${esc($json.list_type || 0)}</list_type>
      <Fields xsi:type="ns2:ArrayOfString">
        ${arr(fields)}
      </Fields>
      <FilterFields xsi:type="ns2:ArrayOfString">
        ${arr(filterFields)}
      </FilterFields>
      <FilterValues xsi:type="ns2:ArrayOfString">
        ${arr(filterValues)}
      </FilterValues>
      <LimitFrom xsi:type="xsd:int">${esc($json.limit_from || 0)}</LimitFrom>
      <LimitCount xsi:type="xsd:int">${esc($json.limit_count || 1)}</LimitCount>
    </ns1:Telemarketing_Outgoing_Get>
  </soap:Body>
</soap:Envelope>`;

return [{ json: { ...$json, crm_filter_fields: filterFields, crm_filter_values: filterValues, soapBody } }];

const base = $items('Build Outgoing_Get SOAP')[0].json;
const raw = $json.data ?? $json.body ?? $json;
const xml = typeof raw === 'string' ? raw : JSON.stringify(raw);

function unesc(s) {
  return String(s)
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&apos;/g, "'")
    .trim();
}

function isUsablePhone(v) {
  const phone = String(v ?? '').trim();
  return phone && phone !== '0';
}

function isFreeStation(v) {
  const stationId = String(v ?? '').trim().toLowerCase();
  return stationId === '' || stationId === '0' || stationId === 'null' || stationId === 'undefined';
}

function boolValue(v) {
  return ['true', '1', 'yes', 'on'].includes(String(v ?? '').trim().toLowerCase());
}

function positiveInt(v, fallback = 1) {
  const n = Math.floor(Number(v));
  if (!Number.isFinite(n) || n < 1) return fallback;
  return n;
}

function cappedParallel(v, fallback = 1) {
  return Math.min(positiveInt(v, fallback), 3);
}

function rawScheduleTo(row) {
  return row.ScheduleTo ?? row.scheduleTo ?? row.schedule_to ?? row.ScheduleDate ?? row.schedule_date ?? '';
}

function parseScheduleTo(v) {
  const raw = String(v ?? '').trim();
  const emptyValues = ['', '0', 'null', 'undefined', '0000-00-00', '0000-00-00 00:00:00'];

  if (emptyValues.includes(raw.toLowerCase())) {
    return { raw, status: 'new_no_schedule', timestamp: null, date_iso: '' };
  }

  let normalized = raw;

  // Common CRM/MySQL format: 2026-06-04 13:20:00.
  if (/^\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}/.test(normalized)) {
    normalized = normalized.replace(/\s+/, 'T');
  }

  // Common EU format fallback: 04/06/2026 13:20:00 or 04.06.2026 13:20:00.
  const eu = normalized.match(/^(\d{2})[./-](\d{2})[./-](\d{4})(?:\s+|T)?(\d{2}:\d{2}(?::\d{2})?)?/);
  if (eu) {
    const [, dd, mm, yyyy, time = '00:00:00'] = eu;
    normalized = `${yyyy}-${mm}-${dd}T${time}`;
  }

  const ts = Date.parse(normalized);

  if (!Number.isFinite(ts)) {
    // Do not block the queue because of an unexpected CRM date format.
    return { raw, status: 'unknown_schedule_format_treated_as_new', timestamp: null, date_iso: '' };
  }

  return { raw, status: 'scheduled', timestamp: ts, date_iso: new Date(ts).toISOString() };
}

function schedulePriority(row, nowMs) {
  const parsed = parseScheduleTo(rawScheduleTo(row));
  const graceMs = 60 * 1000;

  if (parsed.status === 'scheduled') {
    if (parsed.timestamp > nowMs + graceMs) {
      return { ...parsed, bucket: 'future', selectable: false, priority: 99 };
    }

    return { ...parsed, bucket: 'due_schedule', selectable: true, priority: 0 };
  }

  return { ...parsed, bucket: 'new_no_schedule', selectable: true, priority: 1 };
}

const useCompletedGuard = boolValue(base.use_completed_guard);

// Second safety cap: even if Normalize is bypassed or changed, Pick Free Record never starts >3 calls.
const parallelCalls = cappedParallel(base.parallel_calls ?? 1, 1);
const nowMs = Date.now();

const staticData = $getWorkflowStaticData('global');
staticData.telemarketing = staticData.telemarketing || {};
staticData.telemarketing.completedOutgoing = staticData.telemarketing.completedOutgoing || {};
staticData.telemarketing.activeCalls = staticData.telemarketing.activeCalls || {};

function completedKeyFor(row) {
  const telOutgoingId = String(row.TelOutgoingID ?? row.TelOutgoingID_1 ?? '').trim();
  if (!telOutgoingId) return '';
  const scope = base.status_map_storage_key || `${base.BISAPI_URL || base.business_api_url}:${base.BusinessId}:${base.CampaignID}`;
  return `${scope}:${telOutgoingId}`;
}

function legacyCompletedKeyFor(row) {
  const telOutgoingId = String(row.TelOutgoingID ?? row.TelOutgoingID_1 ?? '').trim();
  if (!telOutgoingId) return '';
  return `${base.BusinessId}:${base.CampaignID}:${telOutgoingId}`;
}

function isAlreadyCompleted(row) {
  if (!useCompletedGuard) return false;
  const key = completedKeyFor(row);
  const legacyKey = legacyCompletedKeyFor(row);
  return Boolean((key && staticData.telemarketing.completedOutgoing[key]) || (legacyKey && staticData.telemarketing.completedOutgoing[legacyKey]));
}

const m = xml.match(/<return[^>]*>([\s\S]*?)<\/return>/);
const returnText = m ? unesc(m[1]) : '';

let rows = [];
try {
  rows = returnText ? JSON.parse(returnText) : [];
} catch (e) {
  throw new Error(`Cannot parse Telemarketing_Outgoing_Get return as JSON: ${returnText.slice(0, 500)}`);
}

if (!Array.isArray(rows) || rows.length === 0) {
  console.log('Telemarketing_Outgoing_Get returned no rows.');
  return [];
}

const skippedInfo = [];
const candidates = [];

rows.forEach((r, originalIndex) => {
  const phone = String(r.Mobile || r.Phone || '').trim();
  const stationId = r.StationID ?? r.stationID ?? r.station_id;
  const usablePhone = isUsablePhone(phone);
  const freeStation = isFreeStation(stationId);
  const alreadyCompleted = isAlreadyCompleted(r);
  const schedule = schedulePriority(r, nowMs);

  const selectable = usablePhone && freeStation && !alreadyCompleted && schedule.selectable;

  const info = {
    TelOutgoingID: r.TelOutgoingID ?? r.TelOutgoingID_1 ?? '',
    EntityID: r.EntityID ?? r.entityID ?? r.EntityId ?? '',
    Phone: r.Phone ?? '',
    Mobile: r.Mobile ?? '',
    StationID: r.StationID ?? r.stationID ?? r.station_id ?? '',
    ScheduleTo: rawScheduleTo(r),
    schedule_bucket: schedule.bucket,
    schedule_status: schedule.status,
    schedule_iso: schedule.date_iso,
    usable_phone: usablePhone,
    free_station: freeStation,
    use_completed_guard: useCompletedGuard,
    already_completed_in_workflow: alreadyCompleted,
    selectable,
    selected_for_parallel_call: false,
  };

  if (selectable) {
    candidates.push({ record: r, originalIndex, schedule, info });
  }

  skippedInfo.push(info);
});

// Priority required by curator:
// 1) due ScheduleTo first, oldest due first;
// 2) new/no ScheduleTo after that, preserving CRM order;
// 3) future ScheduleTo is skipped.
candidates.sort((a, b) => {
  if (a.schedule.priority !== b.schedule.priority) return a.schedule.priority - b.schedule.priority;
  if (a.schedule.priority === 0) return (a.schedule.timestamp || 0) - (b.schedule.timestamp || 0);
  return a.originalIndex - b.originalIndex;
});

const selected = candidates.slice(0, parallelCalls);
for (const c of selected) c.info.selected_for_parallel_call = true;

if (selected.length === 0) {
  console.log(`No selectable record found. Returned rows are locked, have no phone, are completed by enabled guard, or have future ScheduleTo: ${JSON.stringify(skippedInfo)}`);
  return [];
}

return selected.map(({ record, schedule }, index) => {
  const to_number = String(record.Mobile || record.Phone || '').trim();
  if (!to_number || to_number === '0') {
    throw new Error(`Selected record has no usable Phone/Mobile: ${JSON.stringify(record)}`);
  }

  const EntityId = String(record.EntityID ?? record.entityID ?? record.EntityId ?? '');
  const summaryKey = `${base.status_map_storage_key || `${base.BusinessId}:${base.CampaignID}`}:${EntityId}`;
  const legacySummaryKey = `${base.BusinessId}:${base.CampaignID}:${EntityId}`;
  const previous_call_summary = staticData.telemarketing?.lastSummaries?.[summaryKey]?.summary || staticData.telemarketing?.lastSummaries?.[legacySummaryKey]?.summary || '';

  return {
    json: {
      ...base,
      crm_get_raw_return: returnText,
      pick_free_record_debug: skippedInfo,
      crm_rows_received: rows.length,
      crm_fetch_limit_used: base.crm_fetch_limit || base.limit_count || '',
      parallel_calls_requested: parallelCalls,
      parallel_calls_selected: selected.length,
      parallel_call_index: index + 1,
      selected_record: record,
      selected_schedule_bucket: schedule.bucket,
      selected_schedule_status: schedule.status,
      selected_schedule_to: schedule.raw,
      selected_schedule_iso: schedule.date_iso,
      TelOutgoingID: String(record.TelOutgoingID ?? record.TelOutgoingID_1 ?? ''),
      EntityId,
      selected_station_id: String(record.StationID ?? record.stationID ?? record.station_id ?? ''),
      to_number,
      Mobile: String(record.Mobile ?? ''),
      Phone: String(record.Phone ?? ''),
      FirstName: String(record.FirstName ?? ''),
      LastName: String(record.LastName ?? ''),
      Email: String(record.Email ?? ''),
      previous_call_summary,
      call_started_at: new Date().toISOString(),
    }
  };
});

function esc(v) {
  return String(v ?? '')
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&apos;');
}
function arr(items) { return items.map(v => `<item xsi:type="xsd:string">${esc(v)}</item>`).join('\n'); }
function dt(d = new Date()) {
  const pad = n => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

return items.map(item => {
  const j = item.json;
  const now = dt();
  const names = ['StationID', 'StationTimeOut', 'userId'];
  const values = [j.station_id || '1000', now, j.userID || '1'];
  const soapBody = `<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/"
    xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
    xmlns:xsd="http://www.w3.org/2001/XMLSchema"
    xmlns:ns1="urn:BusinessApiIntf-IBusinessAPI"
    xmlns:ns2="urn:CommonWSTypes">
    <soap:Body>
      <ns1:Telemarketing_Status_Set soap:encodingStyle="http://schemas.xmlsoap.org/soap/encoding/">
        <ol_EntityID xsi:type="xsd:int">${esc(j.business_entity_id)}</ol_EntityID>
        <ol_Username xsi:type="xsd:string">${esc(j.business_username)}</ol_Username>
        <ol_Password xsi:type="xsd:string">${esc(j.business_password)}</ol_Password>
        <campaignID xsi:type="xsd:int">${esc(j.CampaignID)}</campaignID>
        <EntityId xsi:type="xsd:int">${esc(j.EntityId)}</EntityId>
        <StatusId xsi:type="xsd:int">0</StatusId>
        <CallStarted xsi:type="xsd:string">${esc(now)}</CallStarted>
        <NamesArray xsi:type="ns2:ArrayOfString">${arr(names)}</NamesArray>
        <ValuesArray xsi:type="ns2:ArrayOfString">${arr(values)}</ValuesArray>
      </ns1:Telemarketing_Status_Set>
    </soap:Body>
  </soap:Envelope>`;
  return { json: { ...j, lock_time: now, soapBody } };
});

return items.map(item => {
  const base = item.json;
  const lock_response = base.lock_response ?? base.data ?? base.body ?? base;

  const runStartedAt = String(
    base.run_started_at ||
    base.current_run_started_at ||
    base.call_started_at ||
    new Date().toISOString()
  );

  const dynamic_variables = {
    run_started_at: runStartedAt,
    current_run_started_at: runStartedAt,

    BISAPI_URL: base.BISAPI_URL || base.business_api_url,
    business_api_url: base.business_api_url,
    business_entity_id: base.business_entity_id,
    business_username: base.business_username,
    business_password: base.business_password,

    BusinessId: base.BusinessId,
    campaignID: base.CampaignID,
    CampaignID: base.CampaignID,
    userID: base.userID,

    EntityId: base.EntityId,
    EntityID: base.EntityId,
    TelOutgoingID: base.TelOutgoingID,

    Mobile: base.Mobile,
    Phone: base.Phone,
    to_number: base.to_number,

    FirstName: base.FirstName,
    LastName: base.LastName,
    Email: base.Email,

    station_id: base.station_id,

    status_map_storage_key: base.status_map_storage_key,
    status_map_json: JSON.stringify(base.status_map || {}),

    parallel_call_index: base.parallel_call_index,
    parallel_calls_requested: base.parallel_calls_requested,
    parallel_calls: base.parallel_calls || '1',

    auto_continue_after_callback: String(
      base.auto_continue_after_callback === true ||
      String(base.auto_continue_after_callback).toLowerCase() === 'true'
    ),

    self_start_webhook_url:
      base.self_start_webhook_url ||
      'https://n8n.mekashron.com/webhook/telemarketing-elevenlabs-start',

    crm_fetch_limit: base.crm_fetch_limit || base.limit_count || '100',

    default_final_status_id: base.default_final_status_id,
    failed_start_status_id: base.failed_start_status_id,
    elevenlabs_api_key_for_crm: base.elevenlabs_api_key_for_crm,
  };

  if (base.previous_call_summary) {
    dynamic_variables.previous_call_summary = base.previous_call_summary;
  }

  if (!base.agent_id || !base.agent_phone_number_id || !base.to_number) {
    throw new Error(
