  return {
    json: {
      ...base,
      run_started_at: runStartedAt,
      current_run_started_at: runStartedAt,
      lock_response,
      crm_lock_skipped: false,
      elevenlabs_payload: {
        agent_id: base.agent_id,
        agent_phone_number_id: base.agent_phone_number_id,
        to_number: base.to_number,
        conversation_initiation_client_data: {
          dynamic_variables,
        },
      },
    },
  };
});

const staticData = $getWorkflowStaticData('global');
staticData.telemarketing = staticData.telemarketing || {};
staticData.telemarketing.activeCalls = staticData.telemarketing.activeCalls || {};

return items.map((item, index) => {
  const base = item.json;
  const response = base.elevenlabs_start_response ?? base.body ?? base;
  const conversation_id = response.conversation_id ?? response.conversationId ?? response.conversation?.id ?? response.id ?? '';
  const sip_call_id = response.sip_call_id ?? response.sipCallId ?? response.call_id ?? '';
  const attempt_id = `${base.status_map_storage_key || `${base.BusinessId}:${base.CampaignID}`}:${base.EntityId}:${Date.now()}_${index}`;
  const run_started_at = String(base.run_started_at || base.current_run_started_at || base.call_started_at || new Date().toISOString());

  const record = {
    attempt_id,
    run_started_at,
    current_run_started_at: run_started_at,
    BISAPI_URL: base.BISAPI_URL || base.business_api_url,
    BusinessId: base.BusinessId,
    CampaignID: base.CampaignID,
    userID: base.userID,
    station_id: base.station_id,
    EntityId: base.EntityId,
    TelOutgoingID: base.TelOutgoingID,
    to_number: base.to_number,
    agent_id: base.agent_id,
    agent_phone_number_id: base.agent_phone_number_id,
    conversation_id,
    sip_call_id,
    call_started_at: base.lock_time || base.call_started_at || new Date().toISOString(),
    business_api_url: base.business_api_url,
    business_entity_id: base.business_entity_id,
    business_username: base.business_username,
    business_password: base.business_password,
    elevenlabs_api_key_for_crm: base.elevenlabs_api_key_for_crm,
    status_map: base.status_map,
    status_map_storage_key: base.status_map_storage_key,
    stop_key: base.stop_key,
    default_final_status_id: base.default_final_status_id,
    failed_start_status_id: base.failed_start_status_id,
    auto_continue_after_callback: base.auto_continue_after_callback === true || String(base.auto_continue_after_callback).toLowerCase() === 'true',
    self_start_webhook_url: base.self_start_webhook_url || 'https://n8n.mekashron.com/webhook/telemarketing-elevenlabs-start',
    crm_fetch_limit: base.crm_fetch_limit || base.limit_count || '100',
    parallel_call_index: base.parallel_call_index,
    parallel_calls_requested: base.parallel_calls_requested,
    raw_elevenlabs_start_response: response,
  };

  if (conversation_id) staticData.telemarketing.activeCalls[conversation_id] = record;
  if (sip_call_id) staticData.telemarketing.activeCalls[sip_call_id] = record;
  staticData.telemarketing.activeCalls[attempt_id] = record;

  return {
    json: {
      ...record,
      elevenlabs_start_response: response,
      success: response.success === true,
      failed_before_call_started: response.success !== true,
      failure_message: response.message || '',
    }
  };
});

const body = $json.body ?? $json;
const data = body.data ?? body;
const metadata = data.metadata ?? {};
const phoneCall = metadata.phone_call ?? {};

const dyn =
  data.conversation_initiation_client_data?.dynamic_variables ??
  body.conversation_initiation_client_data?.dynamic_variables ??
  {};

function pick(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v) !== '' && String(v) !== 'undefined') return v;
  }
  return undefined;
}

function boolParam(v, fallback = false) {
  if (v === undefined || v === null || String(v) === '' || String(v) === 'undefined') return fallback;

  const s = String(v).trim().toLowerCase();

  if (['true', '1', 'yes', 'on'].includes(s)) return true;
  if (['false', '0', 'no', 'off'].includes(s)) return false;

  return Boolean(v);
}

function normalizeKey(v) {
  return String(v ?? '')
    .trim()
    .toLowerCase()
    .replace(/[\s\-]+/g, '_')
    .replace(/[^a-z0-9_]/g, '');
}

function normalizeBisapiUrl(v) {
  let url = String(v ?? '').trim();

  if (!url || url === 'undefined') {
    return 'http://lease4.mekashron.com:33330/soap/IBusinessAPI';
  }

  url = url.replace(/\/+$/, '');

  if (/\/soap\/IBusinessAPI$/i.test(url)) return url;

  return `${url}/soap/IBusinessAPI`;
}

function makeScopeKey(bisapiUrl, businessId, campaignId) {
  return `${normalizeBisapiUrl(bisapiUrl)}:${businessId}:${campaignId}`;
}

function parseJsonObject(v) {
  if (!v) return {};

  if (typeof v === 'object' && !Array.isArray(v)) return v;

  if (typeof v === 'string') {
    try {
      const parsed = JSON.parse(v);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
    } catch (e) {}
  }

  return {};
}

function mergeStatusMaps(...maps) {
  const out = {};

  for (const m of maps) {
    if (!m || typeof m !== 'object') continue;

    for (const [k, v] of Object.entries(m)) {
      const key = normalizeKey(k);
      if (!key) continue;
      if (v === undefined || v === null || String(v) === '' || String(v) === 'undefined') continue;
      out[key] = String(v);
    }
  }

  return out;
}

function isoFromUnixSeconds(v) {
  if (v === undefined || v === null || String(v) === '') return '';

  const n = Number(v);
  if (!Number.isFinite(n)) return '';

  return new Date(n * 1000).toISOString();
}

function deriveTranscript(data) {
  const transcript = data.transcript;

  if (Array.isArray(transcript)) {
    return transcript
      .map(t => {
        const role = t.role || '';
        const msg = t.message || t.text || '';
        return msg ? `${role}: ${msg}` : '';
      })
      .filter(Boolean)
      .join('\n');
  }

  if (typeof transcript === 'string') return transcript;

  return '';
}

function deriveSummary(data, transcript) {
  return String(
    pick(
      data.analysis?.transcript_summary,
      data.analysis?.summary,
      data.summary,
      transcript ? transcript.slice(0, 1200) : ''
    )
  );
}

function deriveStatusKey(rawStatus, callSuccessful, terminationReason, hasUserAudio) {
  const raw = normalizeKey(rawStatus);
  const successRaw = normalizeKey(callSuccessful);
  const term = normalizeKey(terminationReason);

  if (['not_interested', 'notinterested'].includes(raw)) return 'not_interested';
  if (['confirm', 'confirmed'].includes(raw)) return 'confirm';
  if (['call_back', 'callback', 'call_later', 'calllater'].includes(raw)) return 'call_back';

  if (['no_answer', 'noanswer', 'not_answered', 'unanswered', 'timeout', 'timed_out'].includes(raw)) {
    return 'no_answer';
  }

  if (['busy', '486'].includes(raw)) return 'busy';

  if (['answering_machine', 'answeringmachine', 'voicemail', 'machine'].includes(raw)) {
    return 'answering_machine';
  }

  if (['invalid_phone', 'invalidphone', 'invalid_number'].includes(raw)) return 'invalid_phone';
  if (['fax'].includes(raw)) return 'fax';

  if (['failed', 'fail', 'failure', 'error', 'sip_error'].includes(raw)) return 'failed';

  if (['success', 'successful', 'true', 'answered', 'completed', 'complete'].includes(successRaw)) {
    return 'answered';
  }

  if (callSuccessful === true) return 'answered';

  if (['success', 'successful', 'answered', 'completed', 'complete'].includes(raw)) {
    return 'answered';
  }

  if (raw === 'done' && (successRaw === 'success' || successRaw === 'true' || hasUserAudio)) {
    return 'answered';
  }

  if (term.includes('busy')) return 'busy';
  if (term.includes('no_answer') || term.includes('timeout')) return 'no_answer';
  if (term.includes('voicemail') || term.includes('answering_machine')) return 'answering_machine';
  if (term.includes('error') || term.includes('failed')) return 'failed';

  return raw || 'answered';
}

const conversation_id = String(
  pick(
    data.conversation_id,
    body.conversation_id,
    data.conversationId,
    body.conversationId,
    data.conversation?.id,
    body.conversation?.id,
    dyn.system__conversation_id,
    ''
  )
);

const sip_call_id = String(
  pick(
    phoneCall.call_sid,
    phoneCall.call_id,
    data.sip_call_id,
    body.sip_call_id,
    dyn.system__call_sid,
    ''
  )
);

const staticData = $getWorkflowStaticData('global');

staticData.telemarketing = staticData.telemarketing || {};
staticData.telemarketing.activeCalls = staticData.telemarketing.activeCalls || {};
staticData.telemarketing.lastSummaries = staticData.telemarketing.lastSummaries || {};
staticData.telemarketing.campaignStatusMaps = staticData.telemarketing.campaignStatusMaps || {};
staticData.telemarketing.currentRuns = staticData.telemarketing.currentRuns || {};

let attempt = null;

if (conversation_id) {
  attempt = staticData.telemarketing.activeCalls[conversation_id];
}

if (!attempt && sip_call_id) {
  attempt = staticData.telemarketing.activeCalls[sip_call_id];
}

if (!attempt && data.attempt_id) {
  attempt = staticData.telemarketing.activeCalls[data.attempt_id];
}

const businessApiUrl = normalizeBisapiUrl(
  pick(
    attempt?.BISAPI_URL,
    attempt?.business_api_url,
    dyn.BISAPI_URL,
    dyn.business_api_url,
    dyn.BisapiUrl,
    ''
  )
);

const businessId = String(pick(attempt?.BusinessId, dyn.BusinessId, dyn.businessId, 1));
const campaignId = String(pick(attempt?.CampaignID, dyn.CampaignID, dyn.campaignID, dyn.campaign_id, 12));
const scopeKey = makeScopeKey(businessApiUrl, businessId, campaignId);
const legacyScopeKey = `${businessId}:${campaignId}`;

const currentRun =
  staticData.telemarketing.currentRuns?.[scopeKey] ||
  staticData.telemarketing.currentRuns?.[legacyScopeKey] ||
  {};

const runStartedAt = String(
  pick(
    attempt?.run_started_at,
    attempt?.current_run_started_at,
    dyn.run_started_at,
    dyn.current_run_started_at,
    currentRun.run_started_at,
    ''
  )
);

const callbackStatusMap = parseJsonObject(dyn.status_map_json);
const storedStatusMap =
  staticData.telemarketing.campaignStatusMaps?.[scopeKey]?.status_map ||
  staticData.telemarketing.campaignStatusMaps?.[legacyScopeKey]?.status_map ||
  {};

const statusMap = mergeStatusMaps(
  {
    no_answer: '1',
    busy: '2',
    invalid_phone: '3',
    fax: '4',
    answering_machine: '5',
  },
  storedStatusMap,
  callbackStatusMap
);

if (!attempt) {
  attempt = {
    attempt_rebuilt_from_callback: true,

    run_started_at: runStartedAt,
    current_run_started_at: runStartedAt,

    BISAPI_URL: businessApiUrl,
    business_api_url: businessApiUrl,

    BusinessId: businessId,
    CampaignID: campaignId,

    userID: String(pick(dyn.userID, dyn.userId, 1)),

    business_entity_id: String(pick(dyn.business_entity_id, dyn.ol_EntityID, '27827')),
    business_username: String(pick(dyn.business_username, dyn.ol_Username, '442033973506')),
    business_password: String(pick(dyn.business_password, dyn.ol_Password, '123456')),

    station_id: String(pick(dyn.station_id, dyn.StationID, '1000')),

    EntityId: String(pick(dyn.EntityId, dyn.EntityID, dyn.entity_id, '')),
    TelOutgoingID: String(pick(dyn.TelOutgoingID, dyn.telOutgoingID, '')),

    Mobile: String(pick(dyn.Mobile, '')),
    Phone: String(pick(dyn.Phone, '')),
    to_number: String(pick(dyn.to_number, dyn.Mobile, dyn.Phone, dyn.system__called_number, '')),

    FirstName: String(pick(dyn.FirstName, '')),
    LastName: String(pick(dyn.LastName, '')),
    Email: String(pick(dyn.Email, '')),

    status_map: statusMap,
    status_map_storage_key: String(pick(dyn.status_map_storage_key, scopeKey)),

    default_final_status_id: String(
      pick(
        dyn.default_final_status_id,
        statusMap.answered,
        statusMap.success,
        statusMap.completed,
        '10'
      )
    ),

    failed_start_status_id: String(
      pick(
        dyn.failed_start_status_id,
        statusMap.failed_start,
        statusMap.failed,
        '10'
      )
    ),

    auto_continue_after_callback: boolParam(dyn.auto_continue_after_callback, false),

    self_start_webhook_url: String(
      pick(
        dyn.self_start_webhook_url,
        'https://n8n.mekashron.com/webhook/telemarketing-elevenlabs-start'
      )
    ),

    crm_fetch_limit: String(pick(dyn.crm_fetch_limit, '100')),
    parallel_calls: String(pick(dyn.parallel_calls, '1')),
    parallel_call_index: dyn.parallel_call_index,
    parallel_calls_requested: dyn.parallel_calls_requested,

    elevenlabs_api_key_for_crm: String(pick(dyn.elevenlabs_api_key_for_crm, '')),

    agent_id: String(pick(data.agent_id, dyn.system__agent_id, '')),
    conversation_id,
    sip_call_id,
  };
} else {
  attempt.run_started_at = String(pick(attempt.run_started_at, dyn.run_started_at, runStartedAt));
  attempt.current_run_started_at = String(pick(attempt.current_run_started_at, dyn.current_run_started_at, runStartedAt));

  attempt.status_map = mergeStatusMaps(statusMap, attempt.status_map || {});
  attempt.status_map_storage_key = attempt.status_map_storage_key || scopeKey;

