    BISAPI_URL: base.BISAPI_URL || base.business_api_url,
    BusinessId: base.BusinessId,
    CampaignID: base.CampaignID,
    EntityId: base.EntityId,
    TelOutgoingID: base.TelOutgoingID,
    to_number: base.to_number,
    final_status_id: base.final_status_id,
    failed_before_call_started: true,
    failure_message: base.failure_message || '',
    run_started_at: runStartedAt,
    completed_at: base.call_ended_at || new Date().toISOString(),
  };

  staticData.telemarketing.completedOutgoing[completedKey] = record;
  staticData.telemarketing.completedOutgoing[legacyCompletedKey] = record;
}

const shouldTriggerNext = Boolean(
  base.auto_continue_after_callback &&
  !stopFlag &&
  base.self_start_webhook_url
);

return [{
  json: {
    ...base,
    run_started_at: runStartedAt,
    current_run_started_at: runStartedAt,
    crm_failed_start_response: crmFailedStartResponse,
    crm_failed_start_result_code: resultCode,
    marked_completed_in_workflow: Boolean(failedStartUpdateOk && base.TelOutgoingID),
    stop_flag_after_failed_start: stopFlag,
    stop_updated_at_after_failed_start: stopCheck.stop_updated_at,
    stale_stop_ignored_after_failed_start: stopCheck.stale_stop_ignored,
    stop_check_after_failed_start: stopCheck,
    should_trigger_next: shouldTriggerNext,
    self_start_webhook_url: base.self_start_webhook_url || '',
  }
}];
